INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10011004, "boss_magic_def_lower_limit", "バトル開始時、すべてのモンスターの魔法防御力を特大アップさせる。この効果は魔法防御力ダウンの影響を受けない。", 4100110, "魔法防御力（ダウン不可）アップ");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10011005, "boss_tp_down_cut", "バトル開始時、すべてのモンスターがＴＰダウン\n50％カット状態になる。", 4100110, "ＴＰダウンカット");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10011006, 3, "バトル開始時、すべてのキャラのＴＰ上昇を中ダウンさせる。", 4100110, "ＴＰ上昇ダウン");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10011007, 9, "バトル開始時、すべてのキャラのＨＰ吸収を特大ダウンさせる。", 4100110, "ＨＰ吸収ダウン");
